**2. Добавить кэширование в `GeoRelayDirectory`**
```swift
// В файле bitchat/Nostr/GeoRelayDirectory.swift
func prefetchIfNeeded(force: Bool = false) {
    let now = dependencies.now()
    let last = dependencies.userDefaults.object(forKey: lastFetchKey) as? Date ?? .distantPast

    // Добавить проверку кэша
    if !force && now.timeIntervalSince(last) < dependencies.fetchInterval {
        return
    }

    // Проверить, изменился ли файл на сервере
    if let cacheURL = dependencies.cacheURL(),
       let cachedData = dependencies.readData(cacheURL),
       let cachedETag = keychain.load(key: "georelay-etag", service: "georelay-cache") {
        // Отправить запрос с If-None-Match
        var request = URLRequest(url: dependencies.remoteURL)
        request.addValue(cachedETag, forHTTPHeaderField: "If-None-Match")
        // ... существующая логика ...
    } else {
        fetchRemote()
    }
}
```

### 5.3. Архитектура

**1. Разделить `BLEService` на сервисы**
```swift
